{
  "integrative": {
    "title": "The Relationship Between Law and Guidance",
    "objective": "Synthesize the distinction between statutory law and non-statutory guidance using the EAWR and BS 7671 as primary examples.",
    "retrievalTextLines": [
      "Statutory regulations like the EAWR are mandatory laws passed by Parliament.",
      "Non-statutory documents like BS 7671 are technical standards that provide guidance on how to comply with those laws.",
      "While they are different in legal status, they work together to ensure electrical safety on site."
    ],
    "questionText": "A colleague argues that BS 7671 and the EAWR are exactly the same because they are both 'the law.' Correct this statement by identifying which one is actually statutory, which is non-statutory, and explaining the functional relationship between them.",
    "answerGuidance": [
      "EAWR is statutory (the law) while BS 7671 is non-statutory (guidance/standard).",
      "BS 7671 provides the technical detail and practical instructions to meet the broad legal requirements set out in the EAWR.",
      "Statutory regulations are mandatory Acts of Parliament, whereas non-statutory documents are industry rulebooks used to demonstrate best practice."
    ],
    "hint": "Think about which one tells you 'you must be safe' (the law) and which one tells you 'how to be safe' (the technical standard)."
  }
}

